import{_ as e,c as t,o as a,a as r}from"./app.015fbf38.js";const x='{"title":"\u8ECA\u80CE\u898F\u683C","description":"","frontmatter":{},"headers":[],"relativePath":"Bike/BikeInfo/\u8ECA\u80CE\u898F\u683C.md","lastUpdated":1648513476165}',o={},n=r('<h1 id="\u8ECA\u80CE\u898F\u683C" tabindex="-1">\u8ECA\u80CE\u898F\u683C <a class="header-anchor" href="#\u8ECA\u80CE\u898F\u683C" aria-hidden="true">#</a></h1><h6 id="tags-\u516C\u8DEF\u8ECA" tabindex="-1">tags: <code>\u516C\u8DEF\u8ECA</code> <a class="header-anchor" href="#tags-\u516C\u8DEF\u8ECA" aria-hidden="true">#</a></h6><p><a href="https://www.mobile01.com/topicdetail.php?f=316&amp;t=4286469#54641993" target="_blank" rel="noopener noreferrer">Reference</a></p><p><strong>700(mm)</strong> \u662F\u516C\u8DEF\u8ECA\u5728\u7528\u7684\u8ECA\u80CE\u898F\u683C\u7684\u5176\u4E2D\u4E00\u7A2E\u6A19\u793A\u6CD5 (ISO) \u81EA\u884C\u8ECA\u9019\u7A2E\u512A\u826F\u4EA4\u901A\u5DE5\u5177\u5728\u5168\u4E16\u754C\u6D41\u901A\uFF0C\u9019\u662F\u597D\u4E8B \u4F46\u4E0D\u5C11\u570B\u5BB6\u90FD\u53EA\u60F3\u4F7F\u7528\u81EA\u5DF1\u7684\u898F\u683C\u6A19\u793A\u6CD5\uFF0C\u6240\u4EE5\u628A\u898F\u683C\u6A19\u793A\u5F04\u5F97\u5F88\u4E82 ISO(\u570B\u969B\u6A19\u6E96\u5316\u7D44\u7E54)\u5F8C\u4F86\u706B\u4E86\uFF0C\u5C31\u8A02\u4E86\u4E00\u500B\u898F\u683C\u5C07\u9019\u4E9B\u6578\u5B57\u9032\u884C\u63DB\u7B97\u8207\u7D71\u4E00 \u4E0D\u5E78\u7684\u662F\uFF0C\u90A3\u4E9B\u81EA\u8A02\u898F\u683C\u7684\u570B\u5BB6\u90E8\u5206\u9084\u662F\u6211\u884C\u6211\u7D20 ISO\u7684\u4ECB\u5165\u65BC\u662F\u53C8\u591A\u9020\u6210\u4E86\u4E00\u500B\u898F\u683C\u7684\u51FA\u73FE\uFF0C\u8B93\u539F\u6709\u7684\u6DF7\u4E82\u8B8A\u5F97\u66F4\u4E82 \u4F46\u9019\u4E26\u4E0D\u5168\u662F\u4ED6\u5011\u7684\u932F\uFF0C\u8AB0\u53EBISO\u8A02\u7684\u898F\u683C\u4E5F\u4E0D\u592A\u9760\u8B5C(\u5F88\u96E3\u7528\u7684\u610F\u601D)...\u03A3(\uFFE3\u25A1\uFFE3||)</p><p>28x13/8x15/8\u9019\u500B\u6578\u5B57\u57FA\u672C\u662F\u9019\u9EBC\u770B\u768428x13/8x15/8 \u4E5F\u5C31\u662F <strong>28\u3000x\u30001\u53C83/8\u3000x\u30001\u53C85/8</strong>\u3000\u3000\u3000\u3000 28(\u540B)\uFF0C\u662F\u6307\u9019\u500B\u8ECA\u80CE\u5145\u6C23\u5F8C\u662F28\u540B\u76F4\u5F91 1\u53C83/8(\u540B)\uFF0C\u662F\u6307\u9019\u500B\u8ECA\u80CE\u5145\u6C23\u5F8C\u7684\u539A\u5EA6 (\u9019\u500B\u6578\u503C\u4E00\u822C\u662F\u7701\u7565) 1\u53C85/8(\u540B)\uFF0C\u662F\u6307\u9019\u500B\u8ECA\u80CE\u5145\u6C23\u5F8C\u7684\u5BEC\u5EA6</p><p>28x13/8x15/8 \u63DB\u7B97\u6B50\u898F\uFF0C\u5927\u62B5\u4E0A\u662F37-622\u7684\u8ECA\u80CE \u63DB\u7B97\u516C\u5236\uFF0C\u5247\u662F700CX35 (\u5F88\u5947\u602A\u5427\uFF0C\u70BA\u4EC0\u9EBC\u4E0D\u662F\u63DB\u7B97\u6210700CX37...\u898F\u683C\u5C31\u662F\u9019\u9EBC\u4E82) \u8DDF\u516C\u8DEF\u8ECA\u768423-622(700CX23)\u76F8\u6BD4\uFF0C\u4F60\u53EF\u4EE5\u770B\u5230\u524D\u9762\u768437\u6578\u5B57\u5F88\u5927\uFF0C\u9019\u500B\u6578\u5B57\u6307\u7684\u662F\u80CE\u5BEC \u9019\u7A2E\u80CE\u662F\u901A\u52E4\u516C\u8DEF\u8ECA\u3001\u8D8A\u91CE\u516C\u8DEF\u8ECA\u5728\u4F7F\u7528\u5C45\u591A\uFF0C\u56E0\u70BA\u8ECA\u80CE\u8F03\u5BEC\uFF0C\u6240\u4EE5\u8ECA\u6846\u4E5F\u6703\u8F03\u5BEC \u4F60\u8981\u81EA\u5DF1\u8CB7\u8ECA\u80CE\u4F86\u63DB\u7684\u8A71\u5C31\u8CB7700CX35\u7684\uFF0C\u800C\u6211\u60F3\u5927\u62B5\u4E0A32-38\u7684\u80CE\u90FD\u80FD\u7528</p><p><strong>\u5C3A\u5BF8\u8D8A\u5927\u7684\u8ECA\u80CE\u901A\u5E38\u8D8A\u539A\uFF0C\u800C\u8D8A\u539A\u7684\u8ECA\u80CE\u652F\u6490\u529B\u901A\u5E38\u8D8A\u5F37</strong> \u4F60\u9019\u689D\u80CE\u4E26\u4E0D\u898B\u5F97\u53EA\u80FD\u625370PSI\uFF0C\u800C\u662F\u53EA\u9700\u8981\u625370PSI\u5C31\u80FD\u9054\u5230\u7406\u60F3\u7684\u8ECA\u80CE\u6548\u80FD\uFF0C\u80CE\u58D3 \u6253\u591A\u4E86\u53EF\u80FD\u6703\u8B93\u8ECA\u80CE\u8B8A\u5F62\uFF0C\u53CD\u800C\u4E0D\u898B\u5F97\u662F\u597D\u4E8B \u9019\u500B\u90E8\u5206\u6709\u5F88\u591A\u5B78\u7406\u5728\uFF0C\u5EE0\u5546\u5EFA\u8B70\u503C\u6709\u4ED6\u7684\u7406\u7531\uFF0C\u4E0D\u9700\u591A\u8AAA\uFF0C\u76F8\u4FE1\u5EE0\u5546\u5C31\u5C0D\u4E86 \u5982\u679C\u8981\u7D30\u7A76\uFF0C\u80CE\u58D3\u8DDF\u9AD4\u91CD\u5176\u5BE6\u9084\u6709\u76F8\u5C0D\u61C9\u95DC\u4FC2 \u8F2A\u80CE\u5EE0\u90FD\u6703\u516C\u5E03\u5C0D\u61C9\u8868\uFF0C\u6BCF\u4E00\u7A2E\u8F2A\u80CE\u5728\u4E0D\u540C\u8F09\u91CD\u4E0B\u9700\u8981\u6253\u591A\u5C11\u6C23\u58D3\uFF0C\u624D\u53EF\u4EE5\u9054\u5230\u6700\u4F73\u7684\u4F7F\u7528\u6548\u80FD</p>',7),s=[n];function _(c,p,d,i,h,l){return a(),t("div",null,s)}var g=e(o,[["render",_]]);export{x as __pageData,g as default};
